VALUES
  ('fire-eq-eng-moex-00743', 'fire-eq-eng', 'fire-eq-eng-moex-104-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依消防機關辦理建築物消防安全設備圖說審查及竣工查驗作業基準之規定，下列何者錯誤？', '["消防安全設備圖說審查之期限，以受理案件後7至10日內結案為原則", "消防機關受理竣工查驗之期限，以受理案件後30日內結案為原則", "完成竣工查驗者，其消防圖說應標明「竣工圖」字樣，送消防機關加蓋驗訖章", "竣工圖消防機關留存二份列管檢查，餘交起造人留存"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:17+00:00", "source_pdf_sha1": "98bf0e3bcf7c", "answer_pdf_sha1": "d4145bb024b1", "source_family": "moex-gov-tw", "moex": {"exam_code": "104060", "c": "401", "s": "0702", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "104", "exam_name": "104年專門驗船師引水人第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00744', 'fire-eq-eng', 'fire-eq-eng-moex-104-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依各類場所消防安全設備設置標準之規定，建築物之各樓層供避難及消防搶救用之有效開口，下列何者 正確？', '["開口下端距樓地板面140公分以內", "開口面臨道路或寬度1公尺以上之通路", "開口有柵欄且內部未設妨礙避難之構造或阻礙物", "開口為可自外面開啟或輕易破壞得以進入室內之構造，採一般玻璃門窗時，厚度應在8毫米以下"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:17+00:00", "source_pdf_sha1": "98bf0e3bcf7c", "answer_pdf_sha1": "d4145bb024b1", "source_family": "moex-gov-tw", "moex": {"exam_code": "104060", "c": "401", "s": "0702", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "104", "exam_name": "104年專門驗船師引水人第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00745', 'fire-eq-eng', 'fire-eq-eng-moex-104-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依防焰性能認證作業規定，下列何者正確？', '["防焰性能認證之申請人為從事防焰物品或其材料之裁剪、縫製、安裝業者時，應經由直轄市、縣（市） 消防機關向內政部申請", "申請案不合程序或有欠缺，其可以補正者，補正期間以2個月為限", "直轄市、縣（市）消防機關於受理申請案經調查後，於10日內附具調查意見表，連同申請書及其相關 資料各二份送內政部審查，餘一份留存消防機關", "經實地調查不合規定時，由內政部檢附審查結果，通知申請人得於文到之日起 3 個月內改善，逾期不 改善或改善不合規定者，應附理由駁回其申請，審查費不予退還"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:17+00:00", "source_pdf_sha1": "98bf0e3bcf7c", "answer_pdf_sha1": "d4145bb024b1", "source_family": "moex-gov-tw", "moex": {"exam_code": "104060", "c": "401", "s": "0702", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "104", "exam_name": "104年專門驗船師引水人第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00746', 'fire-eq-eng', 'fire-eq-eng-moex-104-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依公共危險物品及可燃性高壓氣體設置標準暨安全管理辦法第三章可燃性高壓氣體場所設置及安全管理 之規定，下列何者錯誤？', '["液化石油氣販賣場所儲放之液化石油氣，總儲氣量不得超過128公斤", "液化石油氣儲存場所僅供一家販賣場所使用之面積，不得少於6平方公尺", "容器串接使用場所，串接使用量在120公斤以上未滿300公斤者，容器與用火設備保持2公尺以上距離", "可燃性高壓氣體儲存場所採用不燃材料構造之地面一層建築物，屋頂應以輕質金屬板或其他輕質不燃 材料覆蓋，屋簷並應距離地面2.5公尺以上"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:17+00:00", "source_pdf_sha1": "98bf0e3bcf7c", "answer_pdf_sha1": "d4145bb024b1", "source_family": "moex-gov-tw", "moex": {"exam_code": "104060", "c": "401", "s": "0702", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "104", "exam_name": "104年專門驗船師引水人第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00747', 'fire-eq-eng', 'fire-eq-eng-moex-104-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依防焰性能試驗基準之規定，有關防焰物品或其材料之防焰性能，其餘焰時間之敘述，下列何者正確？', '["薄纖維製品（每平方公尺質量450公克以下者）不得超過5秒", "展示用廣告板不得超過15秒", "厚纖維製品（每平方公尺質量超過450公克者）不得超過10秒", "地毯等地坪舖設物類不得超過20秒"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:17+00:00", "source_pdf_sha1": "98bf0e3bcf7c", "answer_pdf_sha1": "d4145bb024b1", "source_family": "moex-gov-tw", "moex": {"exam_code": "104060", "c": "401", "s": "0702", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "104", "exam_name": "104年專門驗船師引水人第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00748', 'fire-eq-eng', 'fire-eq-eng-moex-104-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依各類場所消防安全設備設置標準規定，各類場所於增建、改建或變更用途時，其消防安全設備之設置， 以下何者適用增建、改建或變更用途前之標準？', '["其消防安全設備為滅火器者", "增建或改建部分，以「各類場所消防安全設備設置標準」中華民國85年7月1日修正條文施行日起， 樓地板面積合計達2,000平方公尺者", "增建或改建部分，以「各類場所消防安全設備設置標準」中華民國85年7月1日修正條文施行日起， 樓地板面積合計達500平方公尺，占原建築物總樓地板面積達二分之一者", "其消防安全設備為自動撒水設備者"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:17+00:00", "source_pdf_sha1": "98bf0e3bcf7c", "answer_pdf_sha1": "d4145bb024b1", "source_family": "moex-gov-tw", "moex": {"exam_code": "104060", "c": "401", "s": "0702", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "104", "exam_name": "104年專門驗船師引水人第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00749', 'fire-eq-eng', 'fire-eq-eng-moex-104-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依公共危險物品及可燃性高壓氣體設置標準暨安全管理辦法之規定，有關六類物品製造場所位置、構造 及設備規定之敘述，下列何者正確？', '["若無積存可燃性蒸氣或可燃性粉塵之虞之建築物，得免除充分之通風設備相關規定", "外牆與加油站之距離應在10公尺以上", "構造不得設於建築物之地下層", "外牆與古蹟之距離應在30公尺以上"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:17+00:00", "source_pdf_sha1": "98bf0e3bcf7c", "answer_pdf_sha1": "d4145bb024b1", "source_family": "moex-gov-tw", "moex": {"exam_code": "104060", "c": "401", "s": "0702", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "104", "exam_name": "104年專門驗船師引水人第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00750', 'fire-eq-eng', 'fire-eq-eng-moex-104-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依公共危險物品及可燃性高壓氣體設置標準暨安全管理辦法之規定，室外儲槽場所儲存易燃液體者，應 設置防液堤，下列何者正確？', '["防液堤高度應在1.5公尺以上", "防液堤內面積不得超過6萬平方公尺", "儲槽容量超過1萬公秉，應在各個儲槽周圍設置分隔堤，分隔堤高度應在30公分以上，且至少低於防 液堤10公分", "防液堤周圍應設道路，並與區內道路連接，道路寬度不得小於6公尺"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:17+00:00", "source_pdf_sha1": "98bf0e3bcf7c", "answer_pdf_sha1": "d4145bb024b1", "source_family": "moex-gov-tw", "moex": {"exam_code": "104060", "c": "401", "s": "0702", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "104", "exam_name": "104年專門驗船師引水人第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00751', 'fire-eq-eng', 'fire-eq-eng-moex-104-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依消防法及消防法施行細則之規定，有關消防防護計畫應包括事項之敘述，下列何者正確？', '["每年應舉辦一次滅火、通報及避難訓練，每次不得少於4小時", "自衛消防編組，若員工30人以下者，應包含滅火、通報、避難引導、安全防護及救護班", "防火避難設施之自行檢查，每兩個月至少檢查一次，檢查結果遇有缺失，應報告管理權人立即改善", "防災應變之教育訓練及防止縱火措施"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:17+00:00", "source_pdf_sha1": "98bf0e3bcf7c", "answer_pdf_sha1": "d4145bb024b1", "source_family": "moex-gov-tw", "moex": {"exam_code": "104060", "c": "401", "s": "0702", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "104", "exam_name": "104年專門驗船師引水人第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00752', 'fire-eq-eng', 'fire-eq-eng-moex-104-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '有關防焰規制敘述，下列何者錯誤？', '["防焰物品或其材料之防焰標示，應經中央主管機關認證具有防焰性能", "防焰物品包括地毯、窗簾、布幕、展示用廣告板及其他指定者", "防焰物品或其材料非附有防焰標示，不得銷售及陳列", "自點火時間終了起，至試樣停止燃燒之時間稱為點火時間"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:17+00:00", "source_pdf_sha1": "98bf0e3bcf7c", "answer_pdf_sha1": "d4145bb024b1", "source_family": "moex-gov-tw", "moex": {"exam_code": "104060", "c": "401", "s": "0702", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "104", "exam_name": "104年專門驗船師引水人第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL)
